CREATE OR REPLACE FUNCTION public.set_updated_at() RETURNS trigger LANGUAGE plpgsql AS $func$ BEGIN NEW.updated_at = now(); RETURN NEW; END; $func$ SET search_path = public;

DO $$ DECLARE r RECORD; v_count INT := 0; BEGIN FOR r IN SELECT c.table_name FROM information_schema.columns c WHERE c.table_schema = 'public' AND c.column_name = 'updated_at' AND c.table_name NOT IN (SELECT viewname FROM pg_views WHERE schemaname = 'public') AND c.table_name NOT IN (SELECT DISTINCT event_object_table FROM information_schema.triggers WHERE trigger_schema = 'public' AND (action_statement LIKE '%updated_at%' OR action_statement LIKE '%update_updated_at%' OR action_statement LIKE '%timestamp%')) LOOP BEGIN EXECUTE format('CREATE TRIGGER trg_set_updated_at BEFORE UPDATE ON public.%I FOR EACH ROW EXECUTE FUNCTION set_updated_at()', r.table_name); v_count := v_count + 1; EXCEPTION WHEN OTHERS THEN RAISE NOTICE 'Skip: % - %', r.table_name, SQLERRM; END; END LOOP; RAISE NOTICE 'Added triggers to % tables', v_count; END $$;;
